'use strict';

/**
* Number of exponent bits for a half-precision floating-point number.
*
* @module @stdlib/constants-float16-num-exponent-bits
* @type {integer16}
*
* @example
* import FLOAT16_NUM_EXPONENT_BITS from '@stdlib/constants-float16-num-exponent-bits';
* // returns 5
*/


// MAIN //

/**
* Number of exponent bits for a half-precision floating-point number.
*
* @constant
* @type {integer16}
* @default 5
*/
var FLOAT16_NUM_EXPONENT_BITS = 5|0;


// EXPORTS //

export default FLOAT16_NUM_EXPONENT_BITS;
